import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { NavigationEnd, Router, RouterLink, RouterLinkActive, RouterOutlet } from '@angular/router';
import { filter } from 'rxjs';
import { AuthService } from '../core/services/auth.service';

interface NavItem {
  label: string;
  icon: string;
  link: string;
  exact?: boolean;
  /** which roles may mutate here — shown to everyone (reads are open), used for hints only. */
  scope?: 'all' | 'admin';
}

/**
 * MiniERP shell: brand header + horizontal top nav on desktop; a hamburger
 * button opening a full-height drawer on mobile (≤768px) — there are more than
 * five destinations, so a drawer (not a bottom tab bar) is used.
 * SMOKE_MARKER: MiniERP
 */
@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterLinkActive, RouterOutlet],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css',
})
export class LayoutComponent implements OnInit {
  private readonly allNav: NavItem[] = [
    { label: 'Dashboard', icon: '📊', link: '/', exact: true, scope: 'all' },
    { label: 'Customers', icon: '👥', link: '/customers', scope: 'all' },
    { label: 'Suppliers', icon: '🏭', link: '/suppliers', scope: 'all' },
    { label: 'Products', icon: '📦', link: '/products', scope: 'all' },
    { label: 'Purchase Orders', icon: '🧾', link: '/purchase-orders', scope: 'all' },
    { label: 'Sales Orders', icon: '🛒', link: '/sales-orders', scope: 'all' },
    { label: 'Invoices', icon: '💳', link: '/invoices', scope: 'all' },
    { label: 'Settings', icon: '⚙️', link: '/admin/settings', scope: 'admin' },
  ];

  readonly drawerOpen = signal(false);

  readonly nav = computed<NavItem[]>(() => {
    const admin = this.auth.isAdmin();
    return this.allNav.filter((n) => (n.scope === 'admin' ? admin : true));
  });

  readonly userName = computed(
    () => this.auth.user()?.name || this.auth.user()?.email || 'Account',
  );
  readonly roleLabel = computed(() => {
    const r = this.auth.role();
    return r ? r.charAt(0).toUpperCase() + r.slice(1) : 'Guest';
  });

  constructor(public auth: AuthService, private router: Router) {}

  ngOnInit(): void {
    // Hydrate the header/nav from the live authenticated user (GET /users/me).
    // Errors keep the cached user (e.g. demo mode) — no redirect here.
    if (this.auth.isLoggedIn()) {
      this.auth.refresh().subscribe({ error: () => {} });
    }
    // Close the drawer whenever navigation completes.
    this.router.events
      .pipe(filter((e) => e instanceof NavigationEnd))
      .subscribe(() => this.drawerOpen.set(false));
  }

  toggleDrawer(): void {
    this.drawerOpen.update((v) => !v);
  }

  logout(): void {
    this.drawerOpen.set(false);
    this.auth.logout();
  }
}
