import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { LayoutComponent } from './shared/layout.component';

/**
 * MiniERP route tree. Hash routing is configured in app.config.ts.
 * `/login` + `/signup` render standalone; everything else is wrapped by
 * LayoutComponent and guarded by `authGuard`. Mutation-scoped areas carry a
 * `roleGuard` reading `data.roles` (products=admin, PO=purchasing, SO/invoices=sales).
 * Each route carries `data.flow.node` for the flow map. Create/edit is driven
 * by `?modal=new` / `?edit=:id` query params restored from ActivatedRoute.
 */
export const routes: Routes = [
  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { node: 'login', entry: true, edgesTo: ['dashboard', 'signup'] } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { node: 'signup', edgesTo: ['dashboard', 'login'] } },
  },
  {
    path: '',
    component: LayoutComponent,
    canActivate: [authGuard],
    children: [
      // ---- Dashboard (default) ----
      {
        path: '',
        pathMatch: 'full',
        loadComponent: () =>
          import('./pages/dashboard/dashboard.component').then((m) => m.DashboardComponent),
        data: { flow: { node: 'dashboard', showInNavbar: true, edgesTo: ['purchase-orders', 'sales-orders', 'invoices'] } },
      },

      // ---- Customers (writes: sales, admin) ----
      {
        path: 'customers',
        loadComponent: () =>
          import('./pages/customers/customers.component').then((m) => m.CustomersComponent),
        data: { roles: ['sales', 'admin'], flow: { node: 'customers', showInNavbar: true, edgesTo: ['customer-detail'] } },
      },
      {
        path: 'customers/:id',
        loadComponent: () =>
          import('./pages/customer-detail/customer-detail.component').then((m) => m.CustomerDetailComponent),
        data: { roles: ['sales', 'admin'], flow: { node: 'customer-detail', edgesTo: ['customers'] } },
      },

      // ---- Suppliers (writes: purchasing, admin) ----
      {
        path: 'suppliers',
        loadComponent: () =>
          import('./pages/suppliers/suppliers.component').then((m) => m.SuppliersComponent),
        data: { roles: ['purchasing', 'admin'], flow: { node: 'suppliers', showInNavbar: true, edgesTo: ['supplier-detail'] } },
      },
      {
        path: 'suppliers/:id',
        loadComponent: () =>
          import('./pages/supplier-detail/supplier-detail.component').then((m) => m.SupplierDetailComponent),
        data: { roles: ['purchasing', 'admin'], flow: { node: 'supplier-detail', edgesTo: ['suppliers'] } },
      },

      // ---- Products (writes: admin) ----
      {
        path: 'products',
        loadComponent: () =>
          import('./pages/products/products.component').then((m) => m.ProductsComponent),
        data: { flow: { node: 'products', showInNavbar: true, edgesTo: ['product-detail'] } },
      },
      {
        path: 'products/:id',
        loadComponent: () =>
          import('./pages/product-detail/product-detail.component').then((m) => m.ProductDetailComponent),
        data: { flow: { node: 'product-detail', edgesTo: ['products'] } },
      },

      // ---- Purchase orders (writes: purchasing, admin) ----
      {
        path: 'purchase-orders',
        loadComponent: () =>
          import('./pages/purchase-orders/purchase-orders.component').then((m) => m.PurchaseOrdersComponent),
        data: { roles: ['purchasing', 'admin'], flow: { node: 'purchase-orders', showInNavbar: true, edgesTo: ['purchase-order-detail'] } },
      },
      {
        path: 'purchase-orders/:id',
        loadComponent: () =>
          import('./pages/purchase-order-detail/purchase-order-detail.component').then((m) => m.PurchaseOrderDetailComponent),
        data: { roles: ['purchasing', 'admin'], flow: { node: 'purchase-order-detail', edgesTo: ['purchase-orders'] } },
      },

      // ---- Sales orders (writes: sales, admin) ----
      {
        path: 'sales-orders',
        loadComponent: () =>
          import('./pages/sales-orders/sales-orders.component').then((m) => m.SalesOrdersComponent),
        data: { roles: ['sales', 'admin'], flow: { node: 'sales-orders', showInNavbar: true, edgesTo: ['sales-order-detail'] } },
      },
      {
        path: 'sales-orders/:id',
        loadComponent: () =>
          import('./pages/sales-order-detail/sales-order-detail.component').then((m) => m.SalesOrderDetailComponent),
        data: { roles: ['sales', 'admin'], flow: { node: 'sales-order-detail', edgesTo: ['sales-orders', 'invoice-detail'] } },
      },

      // ---- Invoices (writes: sales, admin) ----
      {
        path: 'invoices',
        loadComponent: () =>
          import('./pages/invoices/invoices.component').then((m) => m.InvoicesComponent),
        data: { roles: ['sales', 'admin'], flow: { node: 'invoices', showInNavbar: true, edgesTo: ['invoice-detail'] } },
      },
      {
        path: 'invoices/:id',
        loadComponent: () =>
          import('./pages/invoice-detail/invoice-detail.component').then((m) => m.InvoiceDetailComponent),
        data: { roles: ['sales', 'admin'], flow: { node: 'invoice-detail', edgesTo: ['invoices', 'invoice-print'] } },
      },
      {
        path: 'invoices/:id/print',
        loadComponent: () =>
          import('./pages/invoice-print/invoice-print.component').then((m) => m.InvoicePrintComponent),
        data: { roles: ['sales', 'admin'], flow: { node: 'invoice-print', edgesTo: ['invoice-detail'] } },
      },

      // ---- Admin settings ----
      {
        path: 'admin/settings',
        canActivate: [roleGuard],
        loadComponent: () =>
          import('./pages/settings/settings.component').then((m) => m.SettingsComponent),
        data: { roles: ['admin'], flow: { node: 'settings', showInNavbar: true, scope: 'admin', edgesTo: ['dashboard'] } },
      },
    ],
  },

  { path: '**', redirectTo: '' },
];
